{"code": "import json
import re
import pandas as pd
from collections import defaultdict

# Get data from globals
books_key = 'var_functions.query_db:36'
reviews_key = 'var_functions.query_db:38'

all_vars = globals()

books_data = []
reviews_data = []

if books_key in all_vars:
    books_result = all_vars[books_key]
    if isinstance(books_result, str) and '.json' in books_result:
        with open(books_result, 'r') as f:
            books_data = json.load(f)
    else:
        books_data = books_result

if reviews_key in all_vars:
    reviews_result = all_vars[reviews_key]
    if isinstance(reviews_result, str) and '.json' in reviews_result:
        with open(reviews_result, 'r') as f:
            reviews_data = json.load(f)
    else:
        reviews_data = reviews_result

# Check we have data
if not books_data or not reviews_data:
    result = {'error': 'Data not loaded properly', 'books': len(books_data), 'reviews': len(reviews_data)}
else:
    # Extract publication years from books
    book_years = {}
    for book in books_data:
        details = book.get('details', '')
        year_match = re.search(r'((?:19|20)\d{2})', details)
        if year_match:
            year = int(year_match.group(1))
            book_years[book['book_id']] = year

    # Group reviews by book and calculate average ratings
    book_ratings = defaultdict(list)
    for review in reviews_data:
        purchase_id = review.get('purchase_id', '')
        rating = float(review.get('rating', 0))
        book_ratings[purchase_id].append(rating)

    # Calculate decade ratings
    decade_ratings = defaultdict(list)
    decade_book_counts = defaultdict(set)

    for book_id, ratings in book_ratings.items():
        if book_id in book_years:
            year = book_years[book_id]
            decade = (year // 10) * 10
            avg_rating = sum(ratings) / len(ratings)
            decade_ratings[decade].append(avg_rating)
            decade_book_counts[decade].add(book_id)

    # Calculate average rating per decade with at least 10 distinct books
    decade_averages = {}
    book_counts = {decade: len(books) for decade, books in decade_book_counts.items()}

    for decade, ratings in decade_ratings.items():
        if len(decade_book_counts[decade]) >= 10:
            decade_averages[decade] = sum(ratings) / len(ratings)

    # Find decade with highest average rating
    if decade_averages:
        best_decade = max(decade_averages, key=decade_averages.get)
        result = {
            'best_decade': f"{best_decade}s",
            'average_rating': round(decade_averages[best_decade], 2),
            'book_count': book_counts[best_decade],
            'total_decades': len(decade_averages)
        }
    else:
        result = {'error': 'No decades with 10+ books found'}

# Format and print the result
print('__RESULT__:')
print(json.dumps(result))"}

